    '{"prior_uptrend":10,"contraction_count":10,"contraction_depths":18,"volume_dry_up":15,"last_contraction_quality":10,"ma_structure":10,"pivot_readiness":3}'::jsonb
  )
  ) AS rq(id, symbol, source_symbol, source_exchange, source_url, source_date_range, difficulty, base_date, chart_data, actual_next_candles, correct_answer, ai_explanation, rule_score, pattern_evidence, pattern_score_breakdown)
)
INSERT INTO questions (
  id,
  pattern_id,
  symbol,
  market,
  timeframe,
  difficulty,
  market_regime,
  base_date,
  chart_data,
  actual_next_candles,
  correct_answer,
  ai_explanation,
